"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

// ─── Types ────────────────────────────────────────────────────────────────────

type Orientation = "horizontal" | "vertical"

// ─── Stepper context (shared by all sub-components) ───────────────────────────

type StepperContextValue = {
  value: string
  onValueChange: (value: string) => void
  orientation: Orientation
  steps: string[]
  registerStep: (value: string) => void
  unregisterStep: (value: string) => void
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

// ─── StepperItem context (shared within a single step) ────────────────────────

type StepperItemContextValue = {
  value: string
  isActive: boolean
  isCompleted: boolean
  isPending: boolean
  disabled: boolean
}

const StepperItemContext =
  React.createContext<StepperItemContextValue | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

// ─── Stepper ──────────────────────────────────────────────────────────────────

type StepperProps = React.ComponentProps<"div"> & {
  value: string
  onValueChange?: (value: string) => void
  orientation?: Orientation
}

function Stepper({
  value,
  onValueChange,
  orientation = "horizontal",
  className,
  ...props
}: StepperProps) {
  const [steps, setSteps] = React.useState<string[]>([])

  const registerStep = React.useCallback((stepValue: string) => {
    setSteps((prev) => {
      if (prev.includes(stepValue)) return prev
      return [...prev, stepValue]
    })
  }, [])

  const unregisterStep = React.useCallback((stepValue: string) => {
    setSteps((prev) => prev.filter((v) => v !== stepValue))
  }, [])

  return (
    <StepperContext.Provider
      value={{
        value,
        onValueChange: onValueChange ?? (() => {}),
        orientation,
        steps,
        registerStep,
        unregisterStep,
      }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex gap-6",
          orientation === "horizontal" ? "flex-col" : "flex-row items-start",
          className
        )}
        {...props}
      />
    </StepperContext.Provider>
  )
}

// ─── StepperList ──────────────────────────────────────────────────────────────

function StepperList({ className, ...props }: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-list"
      data-orientation={orientation}
      className={cn(
        "flex",
        orientation === "horizontal"
          ? "flex-row items-center"
          : "flex-col items-start",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperItem ──────────────────────────────────────────────────────────────

type StepperItemProps = React.ComponentProps<"div"> & {
  value: string
  disabled?: boolean
}

function StepperItem({
  value,
  disabled = false,
  className,
  ...props
}: StepperItemProps) {
  const {
    value: activeValue,
    steps,
    orientation,
    registerStep,
    unregisterStep,
  } = useStepper()

  React.useEffect(() => {
    registerStep(value)
    return () => unregisterStep(value)
  }, [value, registerStep, unregisterStep])

  const index = steps.indexOf(value)
  const activeIndex = steps.indexOf(activeValue)
  const isActive = activeValue === value
  const isCompleted =
    index !== -1 && activeIndex !== -1 && index < activeIndex
  const isPending = !isActive && !isCompleted

  return (
    <StepperItemContext.Provider
      value={{ value, isActive, isCompleted, isPending, disabled }}
    >
      <div
        data-slot="stepper-item"
        data-state={isActive ? "active" : isCompleted ? "completed" : "pending"}
        data-disabled={disabled ? "" : undefined}
        data-orientation={orientation}
        className={cn(
          "group/stepper-item flex",
          orientation === "horizontal"
            ? "flex-1 items-center last:flex-none"
            : "flex-col items-start",
          disabled && "pointer-events-none opacity-50",
          className
        )}
        {...props}
      />
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ───────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = useStepper()
  const { value, isActive, isCompleted, disabled } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-state={isActive ? "active" : isCompleted ? "completed" : "pending"}
      disabled={disabled}
      aria-current={isActive ? "step" : undefined}
      onClick={() => onValueChange(value)}
      className={cn(
        "group/stepper-trigger inline-flex shrink-0 cursor-pointer items-center gap-2 rounded-sm text-left text-sm transition-colors",
        "outline-none focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50",
        "disabled:pointer-events-none disabled:opacity-50",
        "data-[state=pending]:text-muted-foreground",
        "data-[state=active]:text-foreground",
        "data-[state=completed]:text-foreground",
        className
      )}
      {...props}
    >
      {children}
    </button>
  )
}

// ─── StepperTitle ─────────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("text-sm font-medium leading-none", className)}
      {...props}
    />
  )
}

// ─── StepperDescription ───────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

// ─── StepperSeparator ─────────────────────────────────────────────────────────

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
