"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"
import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperDescription,
  StepperItem,
  StepperList,
  StepperPanel,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
  useStepperItem,
} from "@/registry/new-york-v4/ui/stepper"

const STEPS = [
  {
    value: "details",
    title: "Your details",
    description: "Name and email",
  },
  {
    value: "company",
    title: "Company info",
    description: "Your company or team",
  },
  {
    value: "invite",
    title: "Invite team",
    description: "Get colleagues on board",
  },
]

function StepIndicator({ step }: { step: number }) {
  const { isActive, isCompleted } = useStepperItem()

  return (
    <span
      className={cn(
        "flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-xs font-semibold transition-colors",
        isCompleted || isActive
          ? "border-primary bg-primary text-primary-foreground"
          : "border-muted-foreground/30 bg-background text-muted-foreground"
      )}
    >
      {isCompleted ? <CheckIcon className="size-4" /> : step}
    </span>
  )
}

export default function StepperDemo() {
  const [currentStep, setCurrentStep] = React.useState("details")
  const currentIndex = STEPS.findIndex((s) => s.value === currentStep)

  const handleNext = () => {
    if (currentIndex < STEPS.length - 1) {
      setCurrentStep(STEPS[currentIndex + 1].value)
    }
  }

  const handleBack = () => {
    if (currentIndex > 0) {
      setCurrentStep(STEPS[currentIndex - 1].value)
    }
  }

  return (
    <div className="w-full max-w-2xl">
      <Stepper value={currentStep} onValueChange={setCurrentStep}>
        <StepperList>
          {STEPS.map((step, index) => (
            <StepperItem key={step.value} value={step.value}>
              <StepperTrigger className="gap-3">
                <StepIndicator step={index + 1} />
                <div className="hidden flex-col sm:flex">
                  <StepperTitle>{step.title}</StepperTitle>
                  <StepperDescription>{step.description}</StepperDescription>
                </div>
              </StepperTrigger>
              {index < STEPS.length - 1 && <StepperSeparator />}
            </StepperItem>
          ))}
        </StepperList>

        {STEPS.map((step) => (
          <StepperPanel
            key={step.value}
            value={step.value}
            className="rounded-lg border p-6"
          >
            <p className="text-sm font-medium">{step.title}</p>
            <p className="mt-1 text-sm text-muted-foreground">
              Content for &ldquo;{step.title}&rdquo; goes here.
            </p>
          </StepperPanel>
        ))}

        <div className="flex justify-between">
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={currentIndex === 0}
          >
            Back
          </Button>
          <Button
            onClick={handleNext}
            disabled={currentIndex === STEPS.length - 1}
          >
            {currentIndex === STEPS.length - 1 ? "Finish" : "Continue"}
          </Button>
        </div>
      </Stepper>
    </div>
  )
}

